script:
BURL=$(az keyvault secret show --vault-name SDN-YooVault --name edge-bridge-url --query value -o tsv); BTOK=$(az keyvault secret show --vault-name SDN-YooVault --name edge-bridge-token --query value -o tsv); echo url=$BURL; echo tok-len=${#BTOK}; echo; echo '=== GET / ==='; curl -s -w '
  HTTP=%{http_code}
' -H "Authorization: Bearer $BTOK" "$BURL/" | head -c 400; echo; echo; echo '=== POST /edge/list_tabs ==='; curl -s -w '
  HTTP=%{http_code}
' -X POST -H "Authorization: Bearer $BTOK" "$BURL/edge/list_tabs" | head -c 1200; echo
